1	import { _decorator, error, log } from "cc";
2	import GameView from "../GameView";
3	import { BaseState, commonGameManager, eventManager, msgBoxManager, newBottombarManager, newExtraManager, stateManager } from "db://astarte-framework/Managers";
4	import { CommonState, Define } from "db://astarte-framework/utilis";
5	import Game_Define, { FeverGameType } from "../Game_Define";
6	import { FREE_GAME_ROUND_UI_EVENT } from "../FreeGame/FreeGameRoundUI";
7	import protocol from "@igs-arcade-division-rd2/uk_872_eyestrike2_proto/ar2es2Proto.js";
8	import { REEL_UI_EVENT } from "../ReelUIManager";
9	import { MULTIPLIER_EVENT } from "../Multiplier/MultiplierManager";
10	import { MAGIC_POT_EVENT } from "../MagicPot/MagicPotController";
11	import { FakeReelBetMode } from "../FakeReelManager";
12	const { ccclass } = _decorator;
13	
14	@ccclass( "UnshowPrepareState" )
15	export class UnshowPrepareState extends BaseState
16	{
17	    private m_gameView: GameView = null;
18	
19	    /** @ch 起始盤面索引 */
20	    private m_startRound: number = 0;
21	
22	    /** @ch 起始盤面資訊 */
23	    private m_startRoundInfo: protocol.ar2es2Proto.IRoundInfo = null;
24	
25	    /** @ch 上一輪累積贏分 */
26	    private m_previousAccumulatedWinValue: number = 0;
27	
28	    /** @ch 未顯示轉軸確認隊列 */
29	    private m_unshowSpinAckQue: protocol.ar2es2Proto.IRoundInfo[] = [];
30	
31	    constructor( gameView: GameView )
32	    {
33	        super();
34	        this.m_gameView = gameView;
35	    }
36	
37	    public async OnEnter()
38	    {
39	        if (!commonGameManager.HasUnshow) {
40	            log("[UnshowPrepareState] No unshow data, skip this state");
41	            return;
42	        }
43	
44	        log("OnEnter State: UnshowPrepare");
45	        newExtraManager.HasUnshow = false;
46	
47	        newBottombarManager.SetBarNodeVisiable(true);
48	        if (this.m_gameView.GameIntro) {
49	            this.m_gameView.GameIntro.node.active = false;
50	        }
51	
52	        this.m_unshowSpinAckQue = this.m_gameView.UnshowSpinAck?.RoundQueue ?? [];
53	        this.m_startRound = Math.trunc(commonGameManager.UnshowStartRound ?? 0);
54	        if (this.m_unshowSpinAckQue.length > 0) {
55	            const lastIndex = this.m_unshowSpinAckQue.length - 1;
56	            if (this.m_startRound < 0 || this.m_startRound > lastIndex) {
57	                error(`[UnshowPrepareState] startRound (${this.m_startRound}) out of range [0, ${lastIndex}]`);
58	                this.m_startRound = Math.min(Math.max(0, this.m_startRound), lastIndex);
59	            }
60	            this.m_gameView.SetUnshowPlateCursor( this.m_startRound );
61	            this.m_startRoundInfo = this.m_unshowSpinAckQue[this.m_startRound];
62	        }
63	        else {
64	            error("[UnshowPrepareState] RoundQueue is empty");
65	            this.m_startRound = 0;
66	            this.m_gameView.SetUnshowPlateCursor( 0 );
67	            this.m_startRoundInfo = null;
68	        }
69	
70	        this.m_previousAccumulatedWinValue = 0;
71	
72	        // 檢查是否為FreeGame 或 RespinGame
73	        if (
74	            this.m_unshowSpinAckQue.length > 1
75	            && this.m_startRound >= 1
76	            && this.m_startRound < this.m_unshowSpinAckQue.length
77	        ) {
78	            let plateSymbol = this.m_startRoundInfo?.PlateQueue?.[0]?.PlateSymbol ?? [];
79	            if (this.m_startRoundInfo.CurrFeverGameType === FeverGameType.FreeGame) {
80	                // 地Bar設定
81	                newBottombarManager.SetEnterFree();
82	
83	                // FG 旗標設定
84	                this.m_gameView.IsFreeGame = true;
85	                this.m_gameView.IsFirstRound = false;
86	
87	                plateSymbol = this.m_startRoundInfo?.PlateQueue?.[0]?.PlateSymbol ?? [];
88	            }
89	            // 原 else（CurrFeverGameType===RespinGame）為不可達死碼已刪：
90	            //   startRound≥1 ⟹ 必在 FreeGame（MG 僅 round 0），CurrFeverGameType 不會是 respin。
91	            //   Respin 中段斷線時 server UnshowStartRound 指回該 RoundInfo，從 plate 0（sub=0）重播整局，
92	            //   IsRespinGame 由流程重入 ENTER_RESPIN 自然重建（BC-8 待 Respin 上線實測）。
93	
94	            // 計算上一輪累積贏分
95	            for (let i = 0; i < this.m_startRound; i++) {
96	                this.m_previousAccumulatedWinValue += this.m_unshowSpinAckQue[i].RoundWin;
97	            }
98	
99	            // 設定起始盤面即上一手盤面
100	            this.m_gameView.SlotReels.SetPlateSymbolForUnshow(plateSymbol);
101	
102	            // 原 if(IsRespinGame) HandleRespinGame()：unshow 不再以 Respin 身分恢復（改 plate 0 重播），
103	            // 此處不再呼叫；HandleRespinGame 方法暫留供 BC-8 實測接線（見方法註解）。
104	        }
105	
106	        // 恢復背景音樂
107	        this.RestoreBgm();
108	
109	        // 恢復UI
110	        await this.RestoreUI();
111	
112	        msgBoxManager.ShowMessageBox(
113	            Define.StringKey.MSGBOX_UNSHOW_BACK,
114	            Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO,
115	            () => {
116	                stateManager.NextState(CommonState.SPIN);
117	            }
118	        );
119	    }
120	
121	    public OnProcess()
122	    {
123	    }
124	
125	    public OnLeave()
126	    {
127	        this.m_startRoundInfo = null;
128	        this.m_previousAccumulatedWinValue = 0;
129	    }
130	
131	    /**
132	     * @ch 恢復FreeGame UI
133	     */
134	    private RestoreFreeGameUI()
135	    {
136	        log( "RestoreFreeGameUI" );
137	
138	        // 初始化免費遊戲回合數字
139	        const nowRound = this.m_startRoundInfo?.FreeNowRound ?? 0;
140	        const totalRound = this.GetFreeGameTotalRound();
141	        eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.INIT, nowRound, totalRound );
142	        eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.SHOW );
143	
144	        // 恢復贏分
145	        this.RestoreWinValue();
146	    }
147	
148	    /**
149	     * @ch 恢復RespinGame UI
150	     */
151	    private RestoreRespinGameUI()
152	    {
153	        log( "RestoreRespinGameUI" );
154	
155	        // 恢復贏分
156	        this.RestoreWinValue();
157	    }
158	
159	    /**
160	     * @ch 恢復MainGame UI
161	     */
162	    private RestoreMainGameUI()
163	    {
164	        log( "RestoreMainGameUI" );
165	
166	        // 若有需要恢復其他UI，請在此處實作
167	    }
168	
169	    /**
170	     * @ch 恢復Extra Bet UI
171	     */
172	    private async RestoreExtraBetUI()
173	    {
174	        log( "RestoreExtraBetUI" );
175	
176	        // 先把假轉輪 betMode 快取設好，避免 ForceSetExtraBet 內 ChangeMultiBet 連帶讀到舊值
177	        this.m_gameView.ForceSetFakeReelBetMode(FakeReelBetMode.ExtraBet);
178	        await this.m_gameView.RestoreExtraBetState();
179	    }
180	
181	    /**
182	     * @ch 恢復所有UI
183	     */
184	    private async RestoreUI()
185	    {
186	        this.m_gameView.CheckBackground();
187	        if (this.m_gameView.IsFreeGame) {
188	            this.RestoreFreeGameUI();
189	        }
190	        else if (this.m_gameView.IsRespinGame) {
191	            this.RestoreRespinGameUI();
192	        }
193	        else {
194	            this.RestoreMainGameUI();
195	        }
196	
197	        if (this.m_startRoundInfo) {
198	            // // 設定倍率
199	            // eventManager.Dispatch(MULTIPLIER_EVENT.SET_INDEX, this.m_startRoundInfo.PreMultiplierIndex, true);
200	
201	            // 設定魔法罐等級
202	            eventManager.Dispatch(MAGIC_POT_EVENT.SET_LEVEL, this.m_startRoundInfo.PreScAccuStage);
203	        }
204	
205	        if (this.m_gameView.UnshowSpinAck != null && commonGameManager.UnshowBaseBet < commonGameManager.UnshowRealBet) {
206	            await this.RestoreExtraBetUI();
207	        }
208	    }
209	
210	    /**
211	     * @ch 恢復贏分
212	     */
213	    private RestoreWinValue()
214	    {
215	        log( "RestoreWinValue" );
216	
217	        const totalWin = this.m_gameView.UnshowSpinAck?.TotalWin ?? 0;
218	        newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: this.m_previousAccumulatedWinValue } );
219	    }
220	
221	    /**
222	     * @ch 取得免費遊戲總回合數
223	     * @return 免費遊戲總回合數
224	     */
225	    private GetFreeGameTotalRound(): number
226	    {
227	        if (this.m_unshowSpinAckQue.length === 0) {
228	            error("[UnshowPrepareState] UnshowSpinAckQue is empty");
229	            return 0;
230	        }
231	
232	        // 如果起始盤面索引大於0，則返回上一輪的免費遊戲總回合數
233	        if (this.m_startRound >= 1 && this.m_startRound < this.m_unshowSpinAckQue.length) {
234	            return this.m_unshowSpinAckQue[this.m_startRound - 1].FreeTotalRound;
235	        }
236	
237	        // 照理來說，這裡應該不會執行到
238	        return this.m_unshowSpinAckQue[0].FreeTotalRound ?? 0;
239	    }
240	
241	    /**
242	     * @ch 處理RespinGame
243	     */
244	    /**@ch ⚠️ BC-8 待實測：unshow Respin 恢復暫改「從 plate 0 重播整局」由 ENTER_RESPIN 重建鎖定，
245	     * 此方法目前無呼叫者。待 Respin 上線後確認 unshow 是否需在 prepare 階段直接鎖列亮燈，
246	     * 屆時恢復呼叫或刪除。 */
247	    private HandleRespinGame()
248	    {
249	        log( "HandleRespinGame" );
250	
251	        // 設定Respin鎖定列的旋轉鎖定
252	        Game_Define.RespinLockColumns.forEach( column => {
253	            this.m_gameView.SlotReels.SetColumnLock( column, true );
254	        } );
255	
256	        // 設定轉輪亮燈一次
257	        eventManager.Dispatch(REEL_UI_EVENT.SHOW_LIGHT_LEFT_REEL);
258	        eventManager.Dispatch(REEL_UI_EVENT.SHOW_LIGHT_RIGHT_REEL);
259	    }
260	
261	    /**
262	     * @ch 恢復背景音樂
263	     */
264	    private RestoreBgm()
265	    {
266	        this.m_gameView.PlayMainGameBgm();
267	        if (this.m_gameView.IsFreeGame) {
268	            this.m_gameView.PauseMainGameBgm();
269	            this.m_gameView.PlayFreeGameBgm();
270	        }
271	    }
272	}

